/**
 * Email notification adapter.
 *
 * Sends notifications via email with template rendering and recipient resolution.
 * Implements NotificationAdapter so it can be registered with
 * NotificationService.registerAdapter().
 *
 * Features:
 * - Template rendering: maps NotificationType to HTML email templates
 * - Recipient resolution: validates and normalizes email addresses
 * - Configurable sender address and SMTP settings
 * - Tracks sent emails in memory for testing/audit
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailConfig {
  /** Default "from" address for outgoing emails. */
  fromAddress: string;
  /** SMTP host (for future production use). */
  smtpHost?: string;
  /** SMTP port (for future production use). */
  smtpPort?: number;
}

export const defaultEmailConfig: EmailConfig = {
  fromAddress: 'noreply@taskflowpro.com',
};

/**
 * Represents a rendered email ready for sending.
 */
export interface RenderedEmail {
  to: string;
  from: string;
  subject: string;
  html: string;
  text: string;
}

/**
 * Template definition for a notification type.
 */
interface EmailTemplate {
  renderSubject(payload: NotificationPayload): string;
  renderHtml(payload: NotificationPayload): string;
  renderText(payload: NotificationPayload): string;
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/**
 * Built-in email templates keyed by NotificationType.
 */
const templates: Record<NotificationType, EmailTemplate> = {
  'order:confirmation': {
    renderSubject(payload) {
      return payload.subject;
    },
    renderHtml(payload) {
      const escapedBody = escapeHtml(payload.body);
      return [
        '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
        '<h1 style="color: #2d3748;">Order Confirmation</h1>',
        `<p>${escapedBody}</p>`,
        '<p style="color: #718096; font-size: 14px;">Thank you for your order!</p>',
        '<hr style="border: none; border-top: 1px solid #e2e8f0;" />',
        '<p style="color: #a0aec0; font-size: 12px;">TaskFlow Pro</p>',
        '</div>',
      ].join('\n');
    },
    renderText(payload) {
      return `Order Confirmation\n\n${payload.body}\n\nThank you for your order!\n\n--\nTaskFlow Pro`;
    },
  },

  'order:status-update': {
    renderSubject(payload) {
      return payload.subject;
    },
    renderHtml(payload) {
      const escapedBody = escapeHtml(payload.body);
      return [
        '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
        '<h1 style="color: #2d3748;">Order Status Update</h1>',
        `<p>${escapedBody}</p>`,
        '<p style="color: #718096; font-size: 14px;">We\'ll keep you updated on any further changes.</p>',
        '<hr style="border: none; border-top: 1px solid #e2e8f0;" />',
        '<p style="color: #a0aec0; font-size: 12px;">TaskFlow Pro</p>',
        '</div>',
      ].join('\n');
    },
    renderText(payload) {
      return `Order Status Update\n\n${payload.body}\n\nWe'll keep you updated on any further changes.\n\n--\nTaskFlow Pro`;
    },
  },

  'user:welcome': {
    renderSubject(payload) {
      return payload.subject;
    },
    renderHtml(payload) {
      const escapedBody = escapeHtml(payload.body);
      return [
        '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
        '<h1 style="color: #2d3748;">Welcome to TaskFlow Pro!</h1>',
        `<p>${escapedBody}</p>`,
        '<p style="color: #718096; font-size: 14px;">Get started by exploring your dashboard.</p>',
        '<hr style="border: none; border-top: 1px solid #e2e8f0;" />',
        '<p style="color: #a0aec0; font-size: 12px;">TaskFlow Pro</p>',
        '</div>',
      ].join('\n');
    },
    renderText(payload) {
      return `Welcome to TaskFlow Pro!\n\n${payload.body}\n\nGet started by exploring your dashboard.\n\n--\nTaskFlow Pro`;
    },
  },

  'user:profile-updated': {
    renderSubject(payload) {
      return payload.subject;
    },
    renderHtml(payload) {
      const escapedBody = escapeHtml(payload.body);
      return [
        '<div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">',
        '<h1 style="color: #2d3748;">Profile Updated</h1>',
        `<p>${escapedBody}</p>`,
        '<p style="color: #718096; font-size: 14px;">If you did not make this change, please contact support.</p>',
        '<hr style="border: none; border-top: 1px solid #e2e8f0;" />',
        '<p style="color: #a0aec0; font-size: 12px;">TaskFlow Pro</p>',
        '</div>',
      ].join('\n');
    },
    renderText(payload) {
      return `Profile Updated\n\n${payload.body}\n\nIf you did not make this change, please contact support.\n\n--\nTaskFlow Pro`;
    },
  },
};

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: RenderedEmail[] = [];

  constructor(private config: EmailConfig = defaultEmailConfig) {}

  /**
   * Resolve and validate the recipient email address.
   * Returns the normalized address or throws if invalid.
   */
  resolveRecipient(recipient: string): string {
    const normalized = recipient.trim().toLowerCase();
    if (!normalized || !normalized.includes('@') || !normalized.includes('.')) {
      throw new Error(`Invalid email recipient: "${recipient}"`);
    }
    return normalized;
  }

  /**
   * Render a NotificationPayload into a full RenderedEmail using the
   * template for the payload's notification type.
   */
  renderEmail(payload: NotificationPayload): RenderedEmail {
    const to = this.resolveRecipient(payload.recipient);
    const template = templates[payload.type];

    return {
      to,
      from: this.config.fromAddress,
      subject: template.renderSubject(payload),
      html: template.renderHtml(payload),
      text: template.renderText(payload),
    };
  }

  /**
   * Send an email notification.
   *
   * Resolves the recipient, renders the template, and delivers the email.
   * In production this would call an SMTP/API provider; currently stores
   * the rendered email in memory.
   */
  async send(payload: NotificationPayload): Promise<void> {
    const rendered = this.renderEmail(payload);

    this.logger.info(
      `Sending email from ${rendered.from} to ${rendered.to}: ${rendered.subject}`,
    );

    // In production, this is where we'd call the SMTP transport / API.
    // e.g., await this.smtpTransport.send(rendered);
    this.sentEmails.push(rendered);
  }

  /**
   * Get all sent emails (rendered form). Useful for testing.
   */
  getSentEmails(): RenderedEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history. Useful for testing.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { EmailAdapter, defaultEmailConfig } from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

describe('EmailAdapter', () => {
  let adapter: EmailAdapter;

  beforeEach(() => {
    adapter = new EmailAdapter();
  });

  describe('channel', () => {
    it('should report email channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('resolveRecipient', () => {
    it('should normalize email to lowercase and trim whitespace', () => {
      expect(adapter.resolveRecipient('  Alice@Example.COM  ')).toBe('alice@example.com');
    });

    it('should throw for empty recipient', () => {
      expect(() => adapter.resolveRecipient('')).toThrow('Invalid email recipient');
    });

    it('should throw for recipient without @', () => {
      expect(() => adapter.resolveRecipient('not-an-email')).toThrow('Invalid email recipient');
    });

    it('should throw for recipient without domain dot', () => {
      expect(() => adapter.resolveRecipient('user@localhost')).toThrow('Invalid email recipient');
    });

    it('should accept valid email addresses', () => {
      expect(adapter.resolveRecipient('user@example.com')).toBe('user@example.com');
      expect(adapter.resolveRecipient('name+tag@domain.co.uk')).toBe('name+tag@domain.co.uk');
    });
  });

  describe('renderEmail', () => {
    it('should render order:confirmation template with HTML and text', () => {
      const payload: NotificationPayload = {
        recipient: 'alice@example.com',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
        channel: 'email',
        type: 'order:confirmation',
      };

      const rendered = adapter.renderEmail(payload);

      expect(rendered.to).toBe('alice@example.com');
      expect(rendered.from).toBe('noreply@taskflowpro.com');
      expect(rendered.subject).toBe('Order Confirmation: order-1');
      expect(rendered.html).toContain('<h1');
      expect(rendered.html).toContain('Order Confirmation');
      expect(rendered.html).toContain('Widget x2');
      expect(rendered.html).toContain('$20.00');
      expect(rendered.html).toContain('TaskFlow Pro');
      expect(rendered.text).toContain('Order Confirmation');
      expect(rendered.text).toContain('Widget x2');
      expect(rendered.text).toContain('Thank you for your order!');
    });

    it('should render order:status-update template', () => {
      const payload: NotificationPayload = {
        recipient: 'bob@example.com',
        subject: 'Order Update: order-2',
        body: 'Your order status has changed from pending to shipped.',
        channel: 'email',
        type: 'order:status-update',
      };

      const rendered = adapter.renderEmail(payload);

      expect(rendered.to).toBe('bob@example.com');
      expect(rendered.subject).toBe('Order Update: order-2');
      expect(rendered.html).toContain('Order Status Update');
      expect(rendered.html).toContain('pending to shipped');
      expect(rendered.text).toContain("We'll keep you updated");
    });

    it('should render user:welcome template', () => {
      const payload: NotificationPayload = {
        recipient: 'newuser@example.com',
        subject: 'Welcome to TaskFlow Pro!',
        body: 'Hello Alice, welcome aboard!',
        channel: 'email',
        type: 'user:welcome',
      };

      const rendered = adapter.renderEmail(payload);

      expect(rendered.html).toContain('Welcome to TaskFlow Pro!');
      expect(rendered.html).toContain('Hello Alice, welcome aboard!');
      expect(rendered.text).toContain('Get started by exploring your dashboard');
    });

    it('should render user:profile-updated template', () => {
      const payload: NotificationPayload = {
        recipient: 'alice@example.com',
        subject: 'Profile Updated',
        body: 'Your profile has been updated.',
        channel: 'email',
        type: 'user:profile-updated',
      };

      const rendered = adapter.renderEmail(payload);

      expect(rendered.html).toContain('Profile Updated');
      expect(rendered.text).toContain('If you did not make this change');
    });

    it('should escape HTML in body content', () => {
      const payload: NotificationPayload = {
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Items: <script>alert("xss")</script> & "quotes"',
        channel: 'email',
        type: 'order:confirmation',
      };

      const rendered = adapter.renderEmail(payload);

      expect(rendered.html).not.toContain('<script>');
      expect(rendered.html).toContain('&lt;script&gt;');
      expect(rendered.html).toContain('&amp;');
      expect(rendered.html).toContain('&quot;quotes&quot;');
    });

    it('should use custom from address when configured', () => {
      const customAdapter = new EmailAdapter({ fromAddress: 'custom@company.com' });
      const payload: NotificationPayload = {
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test body',
        channel: 'email',
        type: 'order:confirmation',
      };

      const rendered = customAdapter.renderEmail(payload);
      expect(rendered.from).toBe('custom@company.com');
    });

    it('should throw when rendering with invalid recipient', () => {
      const payload: NotificationPayload = {
        recipient: 'not-valid',
        subject: 'Test',
        body: 'Test',
        channel: 'email',
        type: 'order:confirmation',
      };

      expect(() => adapter.renderEmail(payload)).toThrow('Invalid email recipient');
    });
  });

  describe('send', () => {
    it('should render and store email on send', async () => {
      const payload: NotificationPayload = {
        recipient: 'alice@example.com',
        subject: 'Order Confirmation: order-1',
        body: 'Your order has been placed.',
        channel: 'email',
        type: 'order:confirmation',
      };

      await adapter.send(payload);

      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(1);
      expect(sent[0]?.to).toBe('alice@example.com');
      expect(sent[0]?.from).toBe('noreply@taskflowpro.com');
      expect(sent[0]?.subject).toBe('Order Confirmation: order-1');
      expect(sent[0]?.html).toContain('<h1');
      expect(sent[0]?.text).toContain('Order Confirmation');
    });

    it('should accumulate multiple sent emails', async () => {
      const payload1: NotificationPayload = {
        recipient: 'alice@example.com',
        subject: 'Email 1',
        body: 'First email',
        channel: 'email',
        type: 'order:confirmation',
      };
      const payload2: NotificationPayload = {
        recipient: 'bob@example.com',
        subject: 'Email 2',
        body: 'Second email',
        channel: 'email',
        type: 'order:status-update',
      };

      await adapter.send(payload1);
      await adapter.send(payload2);

      expect(adapter.getSentEmails()).toHaveLength(2);
    });

    it('should throw on invalid recipient during send', async () => {
      const payload: NotificationPayload = {
        recipient: 'bad-address',
        subject: 'Test',
        body: 'Test',
        channel: 'email',
        type: 'order:confirmation',
      };

      await expect(adapter.send(payload)).rejects.toThrow('Invalid email recipient');
    });
  });

  describe('getSentEmails / clearSentEmails', () => {
    it('should return empty array initially', () => {
      expect(adapter.getSentEmails()).toEqual([]);
    });

    it('should return a copy (not the internal array)', async () => {
      await adapter.send({
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test',
        channel: 'email',
        type: 'order:confirmation',
      });

      const first = adapter.getSentEmails();
      const second = adapter.getSentEmails();
      expect(first).not.toBe(second);
      expect(first).toEqual(second);
    });

    it('should clear all sent emails', async () => {
      await adapter.send({
        recipient: 'alice@example.com',
        subject: 'Test',
        body: 'Test',
        channel: 'email',
        type: 'order:confirmation',
      });

      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });

  describe('defaultEmailConfig', () => {
    it('should have expected default from address', () => {
      expect(defaultEmailConfig.fromAddress).toBe('noreply@taskflowpro.com');
    });
  });
});

